import { useEffect, useRef, useState } from 'react'

import Button from '@mui/material/Button'
import Dialog from '@mui/material/Dialog'
import DialogActions from '@mui/material/DialogActions'
import DialogContent from '@mui/material/DialogContent'
import DialogContentText from '@mui/material/DialogContentText'
import DialogTitle from '@mui/material/DialogTitle'

function LearnBlocker() {
  const [open, setOpen] = useState(false)
  const confirmedRef = useRef(false)

  useEffect(() => {
    // Push a guard entry so browser back lands here first
    window.history.pushState(null, '', window.location.href)

    const handlePopState = () => {
      if (confirmedRef.current) return
      // Re-push to stay on current page while dialog is shown
      window.history.pushState(null, '', window.location.href)
      setOpen(true)
    }

    window.addEventListener('popstate', handlePopState)
    return () => window.removeEventListener('popstate', handlePopState)
  }, [])

  const handleConfirm = () => {
    confirmedRef.current = true
    setOpen(false)
    // history: [..., prevPage, learnPage, guard] — go(-2) lands on prevPage
    window.history.go(-2)
  }

  const handleCancel = () => {
    setOpen(false)
  }

  if (!open) return null

  return (
    <Dialog open onClose={handleCancel}>
      <DialogTitle>학습을 종료할까요?</DialogTitle>
      <DialogContent>
        <DialogContentText>지금 나가면 현재 학습 진행 상황이 저장되지 않습니다.</DialogContentText>
      </DialogContent>
      <DialogActions>
        <Button onClick={handleCancel}>계속 학습</Button>
        <Button onClick={handleConfirm} color="error">
          나가기
        </Button>
      </DialogActions>
    </Dialog>
  )
}

export default LearnBlocker
